{
  "name": "word-memory-master",
  "version": "0.1.0",
  "private": true,
  "description": "Local web app for memorizing English vocabulary via LLM-generated structured cards",
  "type": "module",
  "scripts": {
    "test": "vitest run",
    "test:watch": "vitest"
  },
  "repository": {
    "type": "git",
    "url": "git+https://github.com/ipnono/word-memory-master.git"
  },
  "author": "",
  "license": "ISC"
}

import { defineConfig } from 'vitest/config';

export default defineConfig({
  test: {
    environment: 'node',
    globals: false,
  },
});

import { describe, it, expect, beforeEach } from 'vitest';
import { getSettings } from '../src/storage.js';

// Minimal localStorage stub — Vitest runs in Node, where localStorage
// does not exist by default. We attach a fresh mock to globalThis
// before each test.
function createMockLocalStorage() {
  const store = new Map();
  return {
    getItem: (k) => (store.has(k) ? store.get(k) : null),
    setItem: (k, v) => { store.set(k, String(v)); },
    removeItem: (k) => { store.delete(k); },
    clear: () => { store.clear(); },
  };
}

beforeEach(() => {
  globalThis.localStorage = createMockLocalStorage();
});

describe('storage', () => {
  describe('getSettings', () => {
    it('returns seeded defaults when localStorage is empty', () => {
      const s = getSettings();
      expect(s.apiBaseUrl).toBe('https://api.MiniMax.chat/v1');
      expect(s.model).toBe('MiniMax-M3');
      expect(s.historySize).toBe(30);
      expect(s.useProxy).toBe(false);
      expect(s.useJsonMode).toBe(true);
    });
  });
});

// Local storage wrapper for settings + word history.
// All persistence is via globalThis.localStorage (works in both browser
// and Node tests; in the browser, window.localStorage === globalThis.localStorage).

const SETTINGS_KEY = 'settings';
const WORDS_KEY = 'words';

const DEFAULT_SETTINGS = Object.freeze({
  apiBaseUrl: 'https://api.MiniMax.chat/v1',
  apiKey: '',
  model: 'MiniMax-M3',
  promptTemplate: '', // populated below
  historySize: 30,
  useProxy: false,
  proxyUrl: 'http://localhost:8787/v1',
  voice: 'en-US',
  rate: 1.0,
  pitch: 1.0,
  temperature: 0.7,
  maxTokens: 2000,
  requestTimeoutMs: 30000,
  useJsonMode: true,
});

function getLS() {
  return globalThis.localStorage;
}

export function getSettings() {
  const raw = getLS().getItem(SETTINGS_KEY);
  if (!raw) return { ...DEFAULT_SETTINGS };
  return { ...DEFAULT_SETTINGS, ...JSON.parse(raw) };
}

