:root {
  --bg: #f8f9fa;
  --text: #1a1a1a;
  --muted: #6c757d;
  --accent: #4f46e5;
  --accent-hover: #4338ca;
  --border: #e5e7eb;
  --card-bg: #ffffff;
  --error-bg: #fef2f2;
  --error-text: #b91c1c;
  --success: #10b981;
  --shadow: 0 4px 12px rgba(0,0,0,0.08);
  --radius: 8px;
  --font: -apple-system, BlinkMacSystemFont, "Segoe UI", "PingFang SC", "Microsoft YaHei", sans-serif;
}

* { box-sizing: border-box; }
html, body { margin: 0; padding: 0; height: 100%; }
body {
  font-family: var(--font);
  background: var(--bg);
  color: var(--text);
  line-height: 1.6;
}

.hidden { display: none !important; }

/* Header */
.app-header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 16px 24px;
  background: var(--card-bg);
  border-bottom: 1px solid var(--border);
}
.app-header h1 { margin: 0; font-size: 20px; }
.icon-btn {
  background: none; border: none; cursor: pointer;
  font-size: 20px; padding: 6px 10px; border-radius: var(--radius);
}
.icon-btn:hover { background: var(--bg); }

/* Main */
main {
  max-width: 800px;
  margin: 0 auto;
  padding: 24px;
}

/* Lookup */
.lookup { margin-bottom: 24px; }
#word-input {
  width: 100%;
  padding: 14px 16px;
  font-size: 18px;
  border: 2px solid var(--border);
  border-radius: var(--radius);
  outline: none;
  transition: border-color 0.15s;
}
#word-input:focus { border-color: var(--accent); }
#word-input:disabled { opacity: 0.5; cursor: not-allowed; }

.loading {
  display: flex; align-items: center; gap: 8px;
  margin-top: 12px; color: var(--muted); font-size: 14px;
}
.spinner {
  display: inline-block; width: 16px; height: 16px;
  border: 2px solid var(--border); border-top-color: var(--accent);
  border-radius: 50%; animation: spin 0.8s linear infinite;
}
@keyframes spin { to { transform: rotate(360deg); } }

/* Card */
.card-area {
  background: var(--card-bg);
  padding: 24px;
  border-radius: var(--radius);
  box-shadow: var(--shadow);
}
.card-area h2 { margin-top: 0; font-size: 14px; color: var(--muted); text-transform: uppercase; letter-spacing: 0.05em; }

/* Error */
.error-area {
  background: var(--error-bg); color: var(--error-text);
  padding: 16px; border-radius: var(--radius); margin-bottom: 16px;
}
.error-area pre {
  background: rgba(0,0,0,0.05); padding: 12px; border-radius: 4px;
  overflow: auto; max-height: 240px; font-size: 12px;
}
#retry-btn {
  margin-top: 8px;
  background: var(--accent); color: white; border: none;
  padding: 8px 16px; border-radius: var(--radius); cursor: pointer;
}
#retry-btn:hover { background: var(--accent-hover); }

/* Today's list */
.today-list { margin-top: 24px; }
.today-list h2 { font-size: 16px; color: var(--muted); }
.today-list ul { list-style: none; padding: 0; margin: 0; }
.today-list li {
  display: flex; align-items: center; justify-content: space-between;
  padding: 10px 14px; background: var(--card-bg);
  border: 1px solid var(--border); border-radius: var(--radius);
  margin-bottom: 6px; cursor: pointer;
}
.today-list li:hover { border-color: var(--accent); }
.today-list .delete-btn {
  background: none; border: none; cursor: pointer; color: var(--muted);
  font-size: 16px; padding: 4px 8px; border-radius: 4px;
}
.today-list .delete-btn:hover { color: var(--error-text); background: var(--error-bg); }

/* Settings panel (overlay) */
.settings-panel {
  position: fixed; inset: 0;
  background: rgba(0,0,0,0.4);
  display: flex; align-items: center; justify-content: center;
  z-index: 100;
}
.settings-content {
  background: var(--card-bg);
  border-radius: var(--radius);
  width: min(560px, 92vw);
  max-height: 86vh;
  display: flex; flex-direction: column;
  box-shadow: var(--shadow);
}
.settings-header {
  display: flex; align-items: center; justify-content: space-between;
  padding: 16px 20px; border-bottom: 1px solid var(--border);
}
.settings-header h2 { margin: 0; font-size: 18px; }
.settings-body {
  padding: 16px 20px; overflow-y: auto; flex: 1;
}
.settings-footer {
  padding: 12px 20px; border-top: 1px solid var(--border);
  display: flex; gap: 8px;
}
.settings-footer button {
  background: var(--bg); border: 1px solid var(--border);
  padding: 8px 14px; border-radius: var(--radius); cursor: pointer;
  font-size: 14px;
}
.settings-footer button:hover { border-color: var(--accent); }

/* Settings field rows */
.field-row {
  margin-bottom: 16px;
}
.field-row label {
  display: block; font-weight: 600; font-size: 13px;
  margin-bottom: 4px; color: var(--muted);
}
.field-row .field-control {
  display: flex; gap: 8px; align-items: center;
}
.field-row input[type="text"],
.field-row input[type="number"],
.field-row textarea {
  flex: 1; padding: 8px 10px;
  border: 1px solid var(--border); border-radius: 4px;
  font-size: 14px; font-family: inherit;
}
.field-row textarea {
  min-height: 140px; resize: vertical;
  font-family: ui-monospace, "Cascadia Mono", "Consolas", monospace;
  font-size: 12px;
}
.field-row .reset-btn {
  background: none; border: 1px solid var(--border);
  padding: 4px 8px; border-radius: 4px; cursor: pointer;
  font-size: 12px; color: var(--muted);
}
.field-row .reset-btn:hover { border-color: var(--accent); color: var(--accent); }

// Settings panel UI. Renders editable fields for the user's configuration
// and persists changes via storage.setSettings. Per-field reset-to-default.
//
// Slice #1 covers the 5 fields needed for the very first lookup flow.
// Additional fields (voice / rate / pitch / useProxy / proxyUrl) are
// added in their respective slices.

import { getSettings, setSettings } from './storage.js';
import { DEFAULT_SETTINGS } from './storage-defaults.js';

// Fields rendered in the settings panel for slice #1.
const FIELDS = [
  { key: 'apiBaseUrl',   label: 'API Base URL',         type: 'text' },
  { key: 'apiKey',       label: 'API Key',              type: 'text' },
  { key: 'model',        label: 'Model',                type: 'text' },
  { key: 'promptTemplate', label: 'Prompt Template',    type: 'textarea' },
  { key: 'historySize',  label: 'History injection N',  type: 'number' },
];

export function renderSettings(container) {
  const current = getSettings();
  container.innerHTML = '';
  for (const field of FIELDS) {
    container.appendChild(buildFieldRow(field, current[field.key]));
  }
}

function buildFieldRow(field, value) {
  const row = document.createElement('div');
  row.className = 'field-row';
  row.dataset.key = field.key;

  const label = document.createElement('label');
  label.textContent = field.label;
  label.htmlFor = `field-${field.key}`;
  row.appendChild(label);

  const control = document.createElement('div');
  control.className = 'field-control';

  let input;
  if (field.type === 'textarea') {
    input = document.createElement('textarea');
    input.rows = 8;
  } else {
    input = document.createElement('input');
    input.type = field.type;
    if (field.type === 'number') input.min = '1';
  }
  input.id = `field-${field.key}`;
  input.value = value ?? '';
  input.addEventListener('change', () => {
    const v = field.type === 'number' ? Number(input.value) : input.value;
    setSettings({ [field.key]: v });
  });
  control.appendChild(input);

  const resetBtn = document.createElement('button');
  resetBtn.className = 'reset-btn';
  resetBtn.textContent = '恢复默认';
  resetBtn.addEventListener('click', () => {
    const def = DEFAULT_SETTINGS[field.key];
    input.value = def ?? '';
    setSettings({ [field.key]: def });
  });
  control.appendChild(resetBtn);

  row.appendChild(control);
  return row;
}

export function bindSettingsToggle(openBtnId, closeBtnId, panelId) {
  const openBtn = document.getElementById(openBtnId);
  const closeBtn = document.getElementById(closeBtnId);
  const panel = document.getElementById(panelId);
  const container = panel.querySelector('#settings-fields');

  const open = () => {
    renderSettings(container);
    panel.classList.remove('hidden');
  };
  const close = () => panel.classList.add('hidden');

  openBtn.addEventListener('click', open);
  closeBtn.addEventListener('click', close);
  panel.addEventListener('click', (e) => {
    if (e.target === panel) close();
  });
}

