// App entry. Slice #1 wires the minimal shell:
// - settings panel open/close
// - input submit logs to console (LLM call is slice #2)

import { bindSettingsToggle } from './src/settingsPanel.js';

function init() {
  bindSettingsToggle('settings-btn', 'settings-close', 'settings-panel');

  const input = document.getElementById('word-input');
  const form = document.querySelector('.lookup');
  form.addEventListener('submit', (e) => {
    e.preventDefault();
    const word = input.value.trim();
    if (!word) return;
    // Slice #2 will replace this with the LLM call.
    console.log('[stub] lookup:', word);
  });
}

if (document.readyState === 'loading') {
  document.addEventListener('DOMContentLoaded', init);
} else {
  init();
}

import { describe, it, expect } from 'vitest';
import { buildMessages } from '../src/promptBuilder.js';

describe('promptBuilder', () => {
  describe('buildMessages (slice #2 — basic shape, no JSON schema, no history)', () => {
    it('uses settings.promptTemplate as the system message', () => {
      const settings = { promptTemplate: 'YOU ARE A WORD MEMORY MASTER.' };
      const { system, user } = buildMessages({
        word: 'abandon',
        history: [],
        isFirstWord: true,
        settings,
      });
      expect(system).toBe('YOU ARE A WORD MEMORY MASTER.');
    });

    it('includes the word in the user message', () => {
      const settings = { promptTemplate: 'X' };
      const { user } = buildMessages({
        word: 'ephemeral',
        history: [],
        isFirstWord: true,
        settings,
      });
      expect(user).toContain('ephemeral');
    });

    it('returns the shape {system, user}', () => {
      const result = buildMessages({
        word: 'meticulous',
        history: [],
        isFirstWord: true,
        settings: { promptTemplate: 'P' },
      });
      expect(Object.keys(result).sort()).toEqual(['system', 'user']);
    });
  });
});

// Builds the {system, user} message pair sent to the LLM.
//
// Slice #2: basic shape only — system = settings.promptTemplate,
//           user = "请处理以下单词：{word}".
// Slice #3 will append the JSON schema to the system message.
// Slice #7 will inject history into the user message when non-empty.

export function buildMessages({ word, history, isFirstWord, settings }) {
  const system = settings.promptTemplate;
  const user = `请处理以下单词：${word}`;
  return { system, user };
}

import { describe, it, expect, vi, beforeEach, afterEach } from 'vitest';
import { complete } from '../src/llmClient.js';

describe('llmClient', () => {
  describe('complete (slice #2 — basic POST, no retry, no JSON parsing)', () => {
    let fetchSpy;

    beforeEach(() => {
      fetchSpy = vi.fn().mockResolvedValue({
        ok: true,
        status: 200,
        json: async () => ({
          choices: [{ message: { content: 'OK' } }],
        }),
      });
      globalThis.fetch = fetchSpy;
    });

    afterEach(() => {
      delete globalThis.fetch;
    });

    it('POSTs to {apiBaseUrl}/chat/completions', async () => {
      const settings = { apiBaseUrl: 'https://api.example.com/v1', model: 'm' };
      await complete({ systemMsg: 'S', userMsg: 'U', settings });
      const [calledUrl] = fetchSpy.mock.calls[0];
      expect(calledUrl).toBe('https://api.example.com/v1/chat/completions');
    });

    it('sends an Authorization Bearer header with the API key', async () => {
      const settings = {
        apiBaseUrl: 'https://api.example.com/v1',
        model: 'm',
        apiKey: 'sk-test-1234',
      };
      await complete({ systemMsg: 'S', userMsg: 'U', settings });
      const [, init] = fetchSpy.mock.calls[0];
      expect(init.headers.Authorization).toBe('Bearer sk-test-1234');
    });

    it('sends messages in order: system, then user', async () => {
      const settings = { apiBaseUrl: 'https://api.example.com/v1', model: 'm' };
      await complete({ systemMsg: 'SYS-CONTENT', userMsg: 'USER-CONTENT', settings });
      const [, init] = fetchSpy.mock.calls[0];
      const body = JSON.parse(init.body);
      expect(body.model).toBe('m');
      expect(body.messages).toEqual([
        { role: 'system', content: 'SYS-CONTENT' },
        { role: 'user', content: 'USER-CONTENT' },
      ]);
    });
  });
});

// OpenAI-compatible chat completions client.
//
// Slice #2: basic POST + response text extraction. No JSON parsing,
//           no retry, no proxy, no streaming — those are later slices.

export async function complete({ systemMsg, userMsg, settings }) {
  const url = `${settings.apiBaseUrl}/chat/completions`;
  const headers = {
    'Content-Type': 'application/json',
    Authorization: `Bearer ${settings.apiKey ?? ''}`,
  };
  const body = {
    model: settings.model,
    messages: [
      { role: 'system', content: systemMsg },
      { role: 'user', content: userMsg },
    ],
  };

  const res = await fetch(url, {
    method: 'POST',
    headers,
    body: JSON.stringify(body),
  });

  const data = await res.json();
  const text = data?.choices?.[0]?.message?.content ?? '';
  return { ok: true, text };
}

