// App entry. Wires DOM events to the modules.
//
// Slice #2: lookup word → build messages → call LLM → render raw text.
// Slice #3 will parse JSON + render structured card.
// Slice #4 will auto-save to history.

import { getSettings } from './src/storage.js';
import { buildMessages } from './src/promptBuilder.js';
import { complete } from './src/llmClient.js';
import { bindSettingsToggle } from './src/settingsPanel.js';

function init() {
  bindSettingsToggle('settings-btn', 'settings-close', 'settings-panel');

  const form = document.querySelector('.lookup');
  form.addEventListener('submit', (e) => {
    e.preventDefault();
    const word = document.getElementById('word-input').value.trim();
    if (!word) return;
    handleLookup(word);
  });
}

async function handleLookup(word) {
  const input = document.getElementById('word-input');
  const loading = document.getElementById('loading');
  const cardArea = document.getElementById('card-area');
  const errorArea = document.getElementById('error-area');
  const errorMessage = document.getElementById('error-message');
  const retryBtn = document.getElementById('retry-btn');

  // Reset UI state
  cardArea.classList.add('hidden');
  errorArea.classList.add('hidden');
  cardArea.innerHTML = '';
  errorMessage.textContent = '';

  // Show loading, disable input
  loading.classList.remove('hidden');
  input.disabled = true;

  const settings = getSettings();
  const { system, user } = buildMessages({
    word,
    history: [],
    isFirstWord: true,
    settings,
  });

  const result = await complete({ systemMsg: system, userMsg: user, settings });

  // Hide loading, re-enable input
  loading.classList.add('hidden');
  input.disabled = false;

  if (result.ok) {
    // Slice #3 will replace this with structured rendering + JSON parsing.
    cardArea.classList.remove('hidden');
    const pre = document.createElement('pre');
    pre.textContent = result.text;
    cardArea.appendChild(pre);
  } else {
    errorArea.classList.remove('hidden');
    errorMessage.textContent = result.error;
    retryBtn.onclick = () => handleLookup(word);
  }
}

if (document.readyState === 'loading') {
  document.addEventListener('DOMContentLoaded', init);
} else {
  init();
}

import { describe, it, expect } from 'vitest';
import { validateCard } from '../src/schemaValidator.js';

const VALID_CARD = {
  word: 'abandon',
  phonetic: '/əˈbændən/',
  cefr: 'B2',
  coreMeaning: '放弃；抛弃',
  etymology: {
    rootAffix: 'a- (加强) + bandon (权威/控制)',
    relatedWords: ['ban', 'bandage', 'bandit'],
    logic: '放弃对某物的控制权 → 完全放弃',
  },
  mnemonic: { association: '想象你丢掉王冠的瞬间...' },
  usage: {
    collocations: ['abandon hope', 'abandon oneself to', 'abandon ship'],
    examples: [
      { type: 'daily', en: 'He abandoned his car.', zh: '他把车丢了。' },
      { type: 'academic', en: 'The theory was abandoned.', zh: '该理论被摒弃。' },
    ],
  },
  quiz: { question: '填空：He ___ his car.', answer: 'abandoned' },
  chain: 'After he abandoned his post, the bandit tried to bandage his wounds.',
};

describe('schemaValidator', () => {
  it('accepts a fully valid card', () => {
    const result = validateCard(VALID_CARD);
    expect(result.ok).toBe(true);
    expect(result.card.word).toBe('abandon');
  });

  it('rejects when word is missing', () => {
    const { word, ...rest } = VALID_CARD;
    const result = validateCard(rest);
    expect(result.ok).toBe(false);
    expect(result.errors).toContain('word');
  });

  it('rejects when phonetic is missing', () => {
    const { phonetic, ...rest } = VALID_CARD;
    const result = validateCard(rest);
    expect(result.ok).toBe(false);
    expect(result.errors).toContain('phonetic');
  });

  it('rejects when coreMeaning is missing', () => {
    const { coreMeaning, ...rest } = VALID_CARD;
    const result = validateCard(rest);
    expect(result.ok).toBe(false);
    expect(result.errors).toContain('coreMeaning');
  });

  it('rejects when etymology.relatedWords is not a string array', () => {
    const card = structuredClone(VALID_CARD);
    card.etymology.relatedWords = 'ban, bandage, bandit'; // string, not array
    const result = validateCard(card);
    expect(result.ok).toBe(false);
    expect(result.errors.join(' ')).toMatch(/relatedWords/);
  });

  it('rejects when usage.examples is not an array', () => {
    const card = structuredClone(VALID_CARD);
    card.usage.examples = 'not an array';
    const result = validateCard(card);
    expect(result.ok).toBe(false);
    expect(result.errors.join(' ')).toMatch(/examples/);
  });

  it('rejects when quiz.question is empty string', () => {
    const card = structuredClone(VALID_CARD);
    card.quiz.question = '';
    const result = validateCard(card);
    expect(result.ok).toBe(false);
    expect(result.errors.join(' ')).toMatch(/quiz\.question/);
  });

  it('accepts when chain is missing (optional)', () => {
    const { chain, ...rest } = VALID_CARD;
    const result = validateCard(rest);
    expect(result.ok).toBe(true);
  });
});

// Validates LLM-returned JSON against the canonical card schema.
// Returns {ok: true, card} on success, {ok: false, errors[]} on failure.
//
// Schema (from PRD): word, phonetic, cefr, coreMeaning,
//   etymology {rootAffix, relatedWords[], logic},
//   mnemonic {association},
//   usage {collocations[], examples[{type,en,zh}]},
//   quiz {question, answer},
//   chain (optional).

export function validateCard(obj) {
  const errors = [];

  if (!obj || typeof obj !== 'object') {
    return { ok: false, errors: ['root:not-object'] };
  }

  if (typeof obj.word !== 'string' || !obj.word) errors.push('word');
  if (typeof obj.phonetic !== 'string' || !obj.phonetic) errors.push('phonetic');
  if (typeof obj.coreMeaning !== 'string' || !obj.coreMeaning) errors.push('coreMeaning');

  if (obj.etymology && typeof obj.etymology === 'object') {
    if (!Array.isArray(obj.etymology.relatedWords) ||
        !obj.etymology.relatedWords.every(x => typeof x === 'string')) {
      errors.push('etymology.relatedWords:not-string-array');
    }
  }

  if (obj.usage && typeof obj.usage === 'object') {
    if (!Array.isArray(obj.usage.examples)) errors.push('usage.examples:not-array');
  }

  if (obj.quiz && typeof obj.quiz === 'object') {
    if (typeof obj.quiz.question !== 'string' || !obj.quiz.question) {
      errors.push('quiz.question:empty');
    }
  }

  // chain is optional

  if (errors.length) return { ok: false, errors };
  return { ok: true, card: obj };
}

