import { describe, it, expect, vi, beforeEach, afterEach } from 'vitest';
import { speak, pickVoice } from '../src/ttsEngine.js';

function makeMockSpeechSynthesis() {
  return {
    cancel: vi.fn(),
    speak: vi.fn(),
    getVoices: vi.fn(() => [
      { name: 'Microsoft Aria - English (US)', lang: 'en-US' },
      { name: 'Microsoft Jenny - English (US)', lang: 'en-US' },
      { name: 'Microsoft Xiaoxiao - Chinese', lang: 'zh-CN' },
    ]),
    speaking: false,
  };
}

describe('ttsEngine', () => {
  let mockSS;

  beforeEach(() => {
    mockSS = makeMockSpeechSynthesis();
    globalThis.SpeechSynthesisUtterance = vi.fn(function (text) {
      this.text = text;
      this.voice = null;
      this.rate = 1;
      this.pitch = 1;
      this.lang = '';
    });
    globalThis.speechSynthesis = mockSS;
  });

  afterEach(() => {
    delete globalThis.speechSynthesis;
    delete globalThis.SpeechSynthesisUtterance;
  });

  describe('speak', () => {
    it('cancels any in-flight speech before speaking (avoids overlap)', () => {
      speak('hello');
      expect(mockSS.cancel).toHaveBeenCalledTimes(1);
      expect(mockSS.speak).toHaveBeenCalledTimes(1);
    });

    it('creates an utterance with the given text', () => {
      speak('abandon');
      const utterance = mockSS.speak.mock.calls[0][0];
      expect(utterance.text).toBe('abandon');
    });

    it('applies voice / rate / pitch from opts', () => {
      const voice = { name: 'Aria', lang: 'en-US' };
      speak('hello', { voice, rate: 0.8, pitch: 1.5 });
      const utterance = mockSS.speak.mock.calls[0][0];
      expect(utterance.voice).toBe(voice);
      expect(utterance.rate).toBe(0.8);
      expect(utterance.pitch).toBe(1.5);
    });
  });

  describe('pickVoice', () => {
    it('returns the first voice whose lang starts with the requested tag', () => {
      const voice = pickVoice('en-US');
      expect(voice).toBeTruthy();
      expect(voice.lang).toMatch(/^en-US/);
    });

    it('returns null when no voice matches', () => {
      const voice = pickVoice('xx-XX');
      expect(voice).toBeNull();
    });
  });
});

// Browser SpeechSynthesis wrapper.
//
// speak(text, opts): cancels any in-flight utterance first to avoid
//                    overlap, then speaks with voice/rate/pitch applied.
// pickVoice(lang): returns first SpeechSynthesisVoice whose lang starts
//                  with the requested tag, or null if none match.

export function speak(text, opts = {}) {
  if (typeof speechSynthesis === 'undefined') return;
  speechSynthesis.cancel();
  const utterance = new SpeechSynthesisUtterance(text);
  if (opts.voice) utterance.voice = opts.voice;
  if (opts.rate != null) utterance.rate = opts.rate;
  if (opts.pitch != null) utterance.pitch = opts.pitch;
  speechSynthesis.speak(utterance);
}

export function pickVoice(lang) {
  if (typeof speechSynthesis === 'undefined') return null;
  const voices = speechSynthesis.getVoices() ?? [];
  return voices.find(v => v.lang?.toLowerCase().startsWith(lang.toLowerCase())) ?? null;
}

// Renders a validated card object as an HTMLElement.
//
// Slice #3: text-only render.
// Slice #5: audio buttons (🔊) next to word + each English example.
// Slice #6: will add quiz + rating.

import { speak, pickVoice } from './ttsEngine.js';
import { getSettings } from './storage.js';

function ttsOpts() {
  const s = getSettings();
  return {
    voice: resolveVoice(s.voice),
    rate: s.rate,
    pitch: s.pitch,
  };
}

function resolveVoice(stored) {
  if (typeof speechSynthesis === 'undefined') return null;
  if (!stored) return pickVoice('en-US');
  const voices = speechSynthesis.getVoices() ?? [];
  const byName = voices.find(v => v.name === stored);
  if (byName) return byName;
  // Fall back to treating stored value as a lang tag
  return pickVoice(stored) ?? pickVoice('en-US');
}

export function renderCard(card) {
  const root = document.createElement('article');
  root.className = 'card';

  root.appendChild(renderHeader(card));
  if (card.etymology) root.appendChild(renderEtymology(card.etymology));
  if (card.mnemonic) root.appendChild(renderMnemonic(card.mnemonic));
  if (card.usage) root.appendChild(renderUsage(card.usage));
  if (card.chain) root.appendChild(renderChain(card.chain));

  return root;
}

function el(tag, className, text) {
  const e = document.createElement(tag);
  if (className) e.className = className;
  if (text != null) e.textContent = text;
  return e;
}

function audioBtn(text) {
  const b = document.createElement('button');
  b.className = 'audio-btn';
  b.textContent = '🔊';
  b.title = `朗读：${text}`;
  b.addEventListener('click', () => speak(text, ttsOpts()));
  return b;
}

function renderHeader(card) {
  const h = el('section', 'card-section card-header');
  const titleRow = el('div', 'card-title-row');
  titleRow.appendChild(el('h1', 'card-word', card.word));
  if (card.phonetic) {
    const phonWrap = el('span', 'card-phonetic-wrap');
    phonWrap.appendChild(el('span', 'card-phonetic', card.phonetic));
    phonWrap.appendChild(audioBtn(card.word));
    titleRow.appendChild(phonWrap);
  } else {
    titleRow.appendChild(audioBtn(card.word));
  }
  h.appendChild(titleRow);

  const meta = el('div', 'card-meta');
  if (card.cefr) meta.appendChild(el('span', 'card-cefr', card.cefr));
  h.appendChild(meta);

  if (card.coreMeaning) h.appendChild(el('p', 'card-core', card.coreMeaning));
  return h;
}

function renderEtymology(etym) {
  const s = el('section', 'card-section');
  s.appendChild(el('h2', null, '🧬 基因拆解 (Etymology)'));
  if (etym.rootAffix) s.appendChild(el('p', null, `词根/缀: ${etym.rootAffix}`));
  if (Array.isArray(etym.relatedWords) && etym.relatedWords.length) {
    s.appendChild(el('p', null, `同词根单词: ${etym.relatedWords.join(', ')}`));
  }
  if (etym.logic) s.appendChild(el('p', null, `内在逻辑: ${etym.logic}`));
  return s;
}

function renderMnemonic(mn) {
  const s = el('section', 'card-section');
  s.appendChild(el('h2', null, '💡 记忆钩子 (Mnemonic)'));
  if (mn.association) s.appendChild(el('p', null, mn.association));
  return s;
}

function renderUsage(usage) {
  const s = el('section', 'card-section');
  s.appendChild(el('h2', null, '📝 实战应用 (Usage)'));
  if (Array.isArray(usage.collocations) && usage.collocations.length) {
    s.appendChild(el('p', null, `常见搭配: ${usage.collocations.join(', ')}`));
  }
  if (Array.isArray(usage.examples)) {
    const ex = el('div', 'card-examples');
    for (const ex_i of usage.examples) {
      const item = el('div', `card-example card-example-${ex_i.type}`);
      item.appendChild(el('span', 'card-example-tag', ex_i.type === 'daily' ? '日常' : '学术'));
      const enRow = el('div', 'card-example-en-row');
      enRow.appendChild(el('span', 'card-example-en', ex_i.en ?? ''));
      if (ex_i.en) enRow.appendChild(audioBtn(ex_i.en));
      item.appendChild(enRow);
      if (ex_i.zh) item.appendChild(el('p', 'card-example-zh', ex_i.zh));
      ex.appendChild(item);
    }
    s.appendChild(ex);
  }
  return s;
}

function renderChain(chain) {
  const s = el('section', 'card-section card-chain');
  s.appendChild(el('h2', null, '🧠 大串联'));
  s.appendChild(el('p', null, chain));
  return s;
}

// Settings panel UI. Renders editable fields and persists via storage.
//
// Slice #1: 5 fields (apiBaseUrl, apiKey, model, promptTemplate, historySize).
// Slice #5: + voice, rate, pitch (TTS).
// Slice #10: + useProxy, proxyUrl, export/import buttons.

import { getSettings, setSettings, DEFAULT_SETTINGS } from './storage.js';

const FIELDS = [
  { key: 'apiBaseUrl',     label: 'API Base URL',        type: 'text' },
  { key: 'apiKey',         label: 'API Key',             type: 'text' },
  { key: 'model',          label: 'Model',               type: 'text' },
  { key: 'promptTemplate', label: 'Prompt Template',     type: 'textarea' },
  { key: 'historySize',    label: 'History injection N', type: 'number' },
  { key: 'voice',          label: 'TTS Voice',           type: 'voice' },
  { key: 'rate',           label: 'TTS Rate',            type: 'range', min: 0.5, max: 2, step: 0.1 },
  { key: 'pitch',          label: 'TTS Pitch',           type: 'range', min: 0.5, max: 2, step: 0.1 },
];

export function renderSettings(container) {
  const current = getSettings();
  container.innerHTML = '';
  for (const field of FIELDS) {
    container.appendChild(buildFieldRow(field, current[field.key]));
  }
}

function buildFieldRow(field, value) {
  const row = document.createElement('div');
  row.className = 'field-row';
  row.dataset.key = field.key;

  const label = document.createElement('label');
  label.textContent = field.label;
  label.htmlFor = `field-${field.key}`;
  row.appendChild(label);

  const control = document.createElement('div');
  control.className = 'field-control';

  let input;
  if (field.type === 'textarea') {
    input = document.createElement('textarea');
    input.rows = 8;
    input.value = value ?? '';
    input.addEventListener('change', () => setSettings({ [field.key]: input.value }));
  } else if (field.type === 'voice') {
    input = buildVoiceSelect(value);
    input.addEventListener('change', () => setSettings({ [field.key]: input.value }));
  } else if (field.type === 'range') {
    input = document.createElement('input');
    input.type = 'range';
    input.min = field.min;
    input.max = field.max;
    input.step = field.step;
    input.value = value ?? 1.0;
    input.addEventListener('change', () => setSettings({ [field.key]: Number(input.value) }));
  } else {
    input = document.createElement('input');
    input.type = field.type;
    if (field.type === 'number') input.min = '1';
    input.value = value ?? '';
    input.addEventListener('change', () => {
      const v = field.type === 'number' ? Number(input.value) : input.value;
      setSettings({ [field.key]: v });
    });
  }
  input.id = `field-${field.key}`;
  control.appendChild(input);

  const resetBtn = document.createElement('button');
  resetBtn.className = 'reset-btn';
  resetBtn.textContent = '恢复默认';
  resetBtn.addEventListener('click', () => {
    const def = DEFAULT_SETTINGS[field.key];
    input.value = def ?? '';
    setSettings({ [field.key]: def });
  });
  control.appendChild(resetBtn);

  row.appendChild(control);
  return row;
}

function buildVoiceSelect(currentValue) {
  const sel = document.createElement('select');
  // Default option: en-US lang fallback
  const def = document.createElement('option');
  def.value = '';
  def.textContent = '默认 (en-US)';
  sel.appendChild(def);

  const populate = () => {
    // Remove voice options but keep the default
    while (sel.options.length > 1) sel.remove(1);
    if (typeof speechSynthesis === 'undefined') return;
    const voices = speechSynthesis.getVoices() ?? [];
    for (const v of voices) {
      const opt = document.createElement('option');
      opt.value = v.name;
      opt.textContent = `${v.name} (${v.lang})`;
      sel.appendChild(opt);
    }
    sel.value = currentValue ?? '';
  };

  populate();
  if (typeof speechSynthesis !== 'undefined') {
    speechSynthesis.addEventListener?.('voiceschanged', populate);
  }
  return sel;
}

export function bindSettingsToggle(openBtnId, closeBtnId, panelId) {
  const openBtn = document.getElementById(openBtnId);
  const closeBtn = document.getElementById(closeBtnId);
  const panel = document.getElementById(panelId);
  const container = panel.querySelector('#settings-fields');

  const open = () => {
    renderSettings(container);
    panel.classList.remove('hidden');
  };
  const close = () => panel.classList.add('hidden');

  openBtn.addEventListener('click', open);
  closeBtn.addEventListener('click', close);
  panel.addEventListener('click', (e) => {
    if (e.target === panel) close();
  });
}

