  const raw = getLS().getItem(WORDS_KEY);
  if (!raw) return [];
  return JSON.parse(raw);
}

export function addWord(entry) {
  const words = getWords();
  words.push(entry);
  getLS().setItem(WORDS_KEY, JSON.stringify(words));
  return words;
}

export function deleteWord(id) {
  const words = getWords().filter(w => w.id !== id);
  getLS().setItem(WORDS_KEY, JSON.stringify(words));
  return words;
}

export function updateWordRating(id, rating) {
  const words = getWords().map(w =>
    w.id === id ? { ...w, rating, ratedAt: Date.now() } : w
  );
  getLS().setItem(WORDS_KEY, JSON.stringify(words));
  return words;
}

