edits.newText:
.history-group .delete-btn:hover { color: var(--error-text); background: var(--error-bg); }

.layout {
  display: grid;
  grid-template-columns: 1fr 220px;
  gap: 24px;
  align-items: start;
  margin-top: 16px;
}
.day-list-panel {
  background: var(--card-bg);
  border: 1px solid var(--border);
  border-radius: var(--radius);
  padding: 16px 20px;
  min-height: 200px;
}
.day-list-panel h2 {
  margin: 0 0 12px;
  font-size: 18px;
  color: var(--muted);
}
#day-list-items { list-style: none; padding: 0; margin: 0; }
#day-list-items li {
  display: flex; justify-content: space-between; align-items: center;
  padding: 10px 12px; border: 1px solid var(--border); border-radius: var(--radius);
  margin-bottom: 6px;
  cursor: pointer;
}
#day-list-items li:hover { border-color: var(--accent); }
#day-list-items .delete-btn {
  background: none; border: none; cursor: pointer; color: var(--muted);
  font-size: 14px; padding: 4px 8px; border-radius: 4px;
}
#day-list-items .delete-btn:hover { color: var(--error-text); background: var(--error-bg); }
#day-list-empty { margin: 0; padding: 12px; }
.date-sidebar {
  background: var(--card-bg);
  border: 1px solid var(--border);
  border-radius: var(--radius);
  padding: 16px;
  position: sticky; top: 16px;
}
.date-sidebar h2 {
  margin: 0 0 12px;
  font-size: 16px;
  color: var(--muted);
}
#date-list { list-style: none; padding: 0; margin: 0; }
#date-list li {
  padding: 8px 12px;
  border-radius: 6px;
  cursor: pointer;
  margin-bottom: 4px;
  font-size: 14px;
}
#date-list li:hover { background: var(--hover); }
#date-list li.selected {
  background: var(--accent);
  color: white;
  font-weight: 500;
}
.muted { color: var(--muted); }

@media (max-width: 720px) {
  .layout { grid-template-columns: 1fr; }
  .date-sidebar { position: static; }
}

