function openCard(entry) {
  const cardArea = document.getElementById('card-area');
  cardArea.innerHTML = '';
  cardArea.classList.remove('hidden');
  cardArea.appendChild(renderCard(entry.card, entry));
}

function isToday(ts) {
  const d = new Date(ts);
  const now = new Date();
  return d.getFullYear() === now.getFullYear()
      && d.getMonth() === now.getMonth()
      && d.getDate() === now.getDate();
}

function renderTodayList() {
  const list = document.getElementById('today-list');
  const ul = document.getElementById('today-list-items');
  ul.innerHTML = '';

  const todays = getWords().filter(w => isToday(w.addedAt));
  if (todays.length === 0) {
    list.classList.add('hidden');
    return;
  }
  list.classList.remove('hidden');

  // Sort newest first
  todays.sort((a, b) => b.addedAt - a.addedAt);

  for (const entry of todays) {
    const li = document.createElement('li');

    const wordSpan = document.createElement('span');
    wordSpan.textContent = entry.card.word;
    wordSpan.addEventListener('click', () => openCard(entry));
    li.appendChild(wordSpan);

    const delBtn = document.createElement('button');
    delBtn.className = 'delete-btn';
    delBtn.textContent = '🗑';
    delBtn.title = `删除 "${entry.card.word}"`;
    delBtn.addEventListener('click', (e) => {
      e.stopPropagation();
      if (confirm(`删除 "${entry.card.word}"?`)) {
        deleteWord(entry.id);
        renderTodayList();
      }
    });
    li.appendChild(delBtn);

    ul.appendChild(li);
  }
}

edits.newText:
function openCard(entry) {
  const cardArea = document.getElementById('card-area');
  cardArea.innerHTML = '';
  cardArea.classList.remove('hidden');
  cardArea.appendChild(renderCard(entry.card, entry));
}

function formatDateLabel(dateKey) {
  const today = getDateKey(Date.now());
  if (dateKey === today) return `今天 · ${dateKey}`;
  const yesterday = new Date();
  yesterday.setDate(yesterday.getDate() - 1);
  if (dateKey === getDateKey(yesterday.getTime())) return `昨天 · ${dateKey}`;
  return dateKey;
}

function renderLayout() {
  renderDayList();
  renderDateSidebar();
}

function renderDayList() {
  const titleEl = document.getElementById('day-list-title');
  const ul = document.getElementById('day-list-items');
  const emptyEl = document.getElementById('day-list-empty');
  ul.innerHTML = '';

  titleEl.textContent = formatDateLabel(selectedDate);

  const todays = getWordsByDate(getWords(), selectedDate)
    .sort((a, b) => b.addedAt - a.addedAt);

  if (todays.length === 0) {
    emptyEl.classList.remove('hidden');
    return;
  }
  emptyEl.classList.add('hidden');

  for (const entry of todays) {
    const li = document.createElement('li');

    const wordSpan = document.createElement('span');
    wordSpan.textContent = entry.card.word;
    wordSpan.addEventListener('click', () => openCard(entry));
    li.appendChild(wordSpan);

    const delBtn = document.createElement('button');
    delBtn.className = 'delete-btn';
    delBtn.textContent = '🗑';
    delBtn.title = `删除 "${entry.card.word}"`;
    delBtn.addEventListener('click', (e) => {
      e.stopPropagation();
      if (confirm(`删除 "${entry.card.word}"?`)) {
        deleteWord(entry.id);
        renderLayout();
      }
    });
    li.appendChild(delBtn);

    ul.appendChild(li);
  }
}

function renderDateSidebar() {
  const ul = document.getElementById('date-list');
  ul.innerHTML = '';
  const keys = getDateKeys(getWords());
  for (const key of keys) {
    const li = document.createElement('li');
    li.textContent = formatDateLabel(key);
    if (key === selectedDate) li.classList.add('selected');
    li.addEventListener('click', () => {
      selectedDate = key;
      renderLayout();
    });
    ul.appendChild(li);
  }
}

